5	  // Quote — base premiums and processing fee
6	  it("empty item list yields premium of 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it.todo("a single plain sword yields premium 105 G (100 base + 5 fee)");
14	  it.todo("a single plain amulet yields premium 65 G (60 base + 5 fee)");
15	  it.todo("a single plain staff yields premium 85 G (80 base + 5 fee)");
16	  it.todo("a single plain potion yields premium 45 G (40 base + 5 fee)");
17	
18	  // Components and the "block of 3 alike" rule
19	  it.todo("two runes yield premium 55 G (2x25 base + 5 fee)");
20	  it.todo("three runes form a block: premium 65 G (60 base + 5 fee)");
21	  it.todo("four runes yield premium 105 G (4x25 base + 5 fee, no block)");
22	  it.todo("seven runes yield premium 180 G (175 base + 5 fee)");
23	  it.todo("two runes + one moonstone yield premium 80 G (75 base + 5 fee, no block, different types)");
24	  it.todo("three runes + three moonstones yield premium 125 G (120 base + 5 fee, two separate blocks)");
25	
26	  // Item-level modifiers
27	  it.todo("a cursed sword adds a 50% surcharge on the item's base (premium 165 G with first-insurance fee)");
28	  it.todo("a sword with enchantment 5 adds a 30% surcharge");
29	  it.todo("a sword with enchantment 4 has no high-enchantment surcharge");
30	
31	  // Policy-level modifiers
32	  it.todo("a long-standing customer (>= 2 years) gets a 20% loyalty discount on policy base");
33	  it.todo("the customer's second contract gets a 15% follow-up discount");
34	  it.todo("first insurance adds a 10% surcharge per item in the policy");
35	
36	  // Multi-item policies and modifier scope
37	  it.todo("a cursed sword + plain amulet → 215 G (160 base + 50 curse + first-insurance + fee)");
38	
39	  // Rounding in MHPCO favor for premiums
40	  it.todo("a premium calculation that yields 197.5 G rounds up to 198 G");
41	
42	  // Claim — deductible, cap, special clauses
43	  it.todo("a regular sword (steel, ench 3), damage 500 G → payout 400 G");
44	  it.todo("damage to a rune (value 250 G), damage 200 G → payout 100 G");
45	  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full minus deductible)");
46	  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% then deductible)");
47	  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
48	  it.todo("dragon-material sword, ench 8, damage 1000 G → payout 400 G");
49	
50	  // Multiple damages in one claim
51	  it.todo("a dragon attack on insured sword (500 G) and amulet (300 G) → payout 600 G (deductible per item)");
52	  it.todo("two swords insured; both damaged in one event → each gets its own deductible");
53	
54	  // Cap
55	  it.todo("cap is twice the insurance sum; cap depletes across successive claims");
56	  it.todo("cap is based on unmodified insurance value, not modified premium");
57	
58	  // Rounding for payouts
59	  it.todo("a payout of 350.5 G rounds down to 350 G");
60	
61	  // Errors
62	  it.todo("quote with unknown item type → error result with non-zero exit");
63	  it.todo("claim referencing an item not in the policy → error result");
64	  it.todo("claim with negative damage amount → error result");
65	  it.todo("claim with more damages of a type than the policy covers → error result");
